import bisect
from collections import Counter

class Solution(object):
    def gcdValues(self, nums, queries):
        MAX_VAL = max(nums) + 1
        freq = Counter(nums)
        # cnt_div[g] = number of elements divisible by g
        cnt_div = [0] * MAX_VAL
        for g in range(1, MAX_VAL):
            for m in range(g, MAX_VAL, g):
                cnt_div[g] += freq.get(m, 0)
        # exact[g] = pairs with GCD exactly g (Mobius inversion)
        exact = [0] * MAX_VAL
        for g in range(MAX_VAL - 1, 0, -1):
            exact[g] = cnt_div[g] * (cnt_div[g] - 1) // 2
            for m in range(2 * g, MAX_VAL, g):
                exact[g] -= exact[m]
        # Prefix sum: prefix[g] = number of pairs with GCD <= g
        prefix = [0] * MAX_VAL
        for g in range(1, MAX_VAL):
            prefix[g] = prefix[g-1] + exact[g]
        # Answer queries: find smallest g with prefix[g] >= q+1
        result = []
        for q in queries:
            lo, hi = 1, MAX_VAL - 1
            while lo < hi:
                mid = (lo + hi) // 2
                if prefix[mid] >= q + 1:
                    hi = mid
                else:
                    lo = mid + 1
            result.append(lo)
        return result
